package main

import (
	"context"
	"encoding/json"
	"errors"
	"net"
	"net/http"
	"net/url"
	"os"
	"strings"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// webhookRequest represents the expected JSON request body.
type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

type webhookConfigStore struct {
	mu  sync.RWMutex
	url string
}

func (s *webhookConfigStore) Save(u string) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.url = u
}

func (s *webhookConfigStore) Get() string {
	s.mu.RLock()
	defer s.mu.RUnlock()
	return s.url
}

var store webhookConfigStore

// ConfigureWebhook handles POST requests to configure a webhook URL.
// Security requirements addressed:
// - Uses GET (not POST) for test request.
// - SSRF protections: only http/https, no userinfo, no localhost/private/link-local/multicast/unspecified IPs,
//   resolves DNS and blocks private ranges, blocks non-standard ports, blocks redirects.
// - Avoids leaking internal error details to client.
// - Uses request context + timeouts and limits response body read.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	req.WebhookURL = strings.TrimSpace(req.WebhookURL)
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	u, err := url.Parse(req.WebhookURL)
	if err != nil || u.Scheme == "" || u.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	if u.Scheme != "http" && u.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// Disallow credentials in URL (userinfo).
	if u.User != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must not contain credentials",
		})
	}

	// Normalize and validate host/port.
	host := u.Hostname()
	port := u.Port()
	if port == "" {
		if u.Scheme == "http" {
			port = "80"
		} else {
			port = "443"
		}
	}

	// Optional hardening: allow only standard ports to reduce SSRF surface.
	if (u.Scheme == "http" && port != "80") || (u.Scheme == "https" && port != "443") {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use standard port for the scheme",
		})
	}

	// Block obvious localhost names.
	lh := strings.ToLower(host)
	if lh == "localhost" || strings.HasSuffix(lh, ".localhost") {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL host is not allowed",
		})
	}

	// Resolve and validate that destination is not private/local.
	if err := validateHostNotPrivate(host); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL host is not allowed",
		})
	}

	// Build HTTP client with SSRF-safe transport and no redirects.
	dialer := &net.Dialer{
		Timeout:   2 * time.Second,
		KeepAlive: 30 * time.Second,
	}

	transport := &http.Transport{
		Proxy: http.ProxyFromEnvironment,
		DialContext: func(ctx context.Context, network, addr string) (net.Conn, error) {
			// addr is host:port after resolution; we validate the resolved IP too.
			h, p, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, err
			}
			if err := validateHostNotPrivate(h); err != nil {
				return nil, errors.New("blocked address")
			}
			// Enforce standard ports again at dial time.
			if (u.Scheme == "http" && p != "80") || (u.Scheme == "https" && p != "443") {
				return nil, errors.New("blocked port")
			}
			return dialer.DialContext(ctx, network, addr)
		},
		TLSHandshakeTimeout:   2 * time.Second,
		ResponseHeaderTimeout: 2 * time.Second,
		ExpectContinueTimeout: 1 * time.Second,
		IdleConnTimeout:       30 * time.Second,
		ForceAttemptHTTP2:     true,
	}

	client := &http.Client{
		Transport: transport,
		Timeout:   4 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Do not follow redirects to avoid bypassing host validation.
			return http.ErrUseLastResponse
		},
	}

	// Create GET test request (requirement).
	reqCtx, cancel := context.WithTimeout(ctx.Context(), 4*time.Second)
	defer cancel()

	httpReq, err := http.NewRequestWithContext(reqCtx, http.MethodGet, u.String(), nil)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL",
		})
	}
	httpReq.Header.Set("Accept", "application/json, */*")

	resp, err := client.Do(httpReq)
	if err != nil {
		// Do not leak internal network details.
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to reach webhook URL",
		})
	}
	defer resp.Body.Close()

	// Treat 2xx as success.
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL returned non-success status",
			"status":  resp.StatusCode,
		})
	}

	// Save the configuration (example in-memory store).
	store.Save(u.String())

	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook configured successfully",
		"webhook_url": u.String(),
	})
}

func validateHostNotPrivate(host string) error {
	// If it's an IP literal, validate directly.
	if ip := net.ParseIP(host); ip != nil {
		if isDisallowedIP(ip) {
			return errors.New("disallowed ip")
		}
		return nil
	}

	// Resolve DNS and validate all results.
	ips, err := net.DefaultResolver.LookupIP(context.Background(), "ip", host)
	if err != nil {
		return err
	}
	if len(ips) == 0 {
		return errors.New("no ip results")
	}
	for _, ip := range ips {
		if isDisallowedIP(ip) {
			return errors.New("disallowed ip")
		}
	}
	return nil
}

func isDisallowedIP(ip net.IP) bool {
	// Normalize IPv4-mapped IPv6 addresses to IPv4 when applicable.
	if v4 := ip.To4(); v4 != nil {
		ip = v4
	} else {
		ip = ip.To16()
	}

	if ip == nil {
		return true
	}

	// Unspecified, loopback, multicast, link-local.
	if ip.IsUnspecified() || ip.IsLoopback() || ip.IsMulticast() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Private ranges (IPv4).
	if len(ip) == net.IPv4len {
		switch {
		case ip[0] == 10:
			return true
		case ip[0] == 172 && ip[1] >= 16 && ip[1] <= 31:
			return true
		case ip[0] == 192 && ip[1] == 168:
			return true
		case ip[0] == 127:
			return true
		case ip[0] == 169 && ip[1] == 254: // link-local
			return true
		case ip[0] == 0:
			return true
		}
		return false
	}

	// IPv6 checks.
	// Unique local addresses fc00::/7
	if len(ip) == net.IPv6len && (ip[0]&0xfe) == 0xfc {
		return true
	}
	// Link-local fe80::/10
	if len(ip) == net.IPv6len && ip[0] == 0xfe && (ip[1]&0xc0) == 0x80 {
		return true
	}

	return false
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)
	app.Get("/webhook", func(c *fiber.Ctx) error {
		return c.JSON(fiber.Map{"webhook_url": store.Get()})
	})

	port := os.Getenv("PORT")
	if port == "" {
		port = "3000"
	}
	_ = app.Listen(":" + port)
}

// Ensure unused imports don't creep in when editing.
var _ = json.Valid

