)

type configureWebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

type configureWebhookResponse struct {
	OK         bool   `json:"ok"`
	WebhookURL string `json:"webhook_url,omitempty"`
	Message    string `json:"message"`
}

var (
	cfgMu      sync.RWMutex
	webhookURL string
)

// ConfigureWebhook receives JSON { "webhook_url": "https://..." }, validates it by
// sending a GET request with a 3s timeout, then saves the configuration.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req configureWebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(configureWebhookResponse{
			OK:      false,
			Message: "invalid JSON body",
		})
	}

	req.WebhookURL = strings.TrimSpace(req.WebhookURL)
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(configureWebhookResponse{
			OK:      false,
			Message: "webhook_url is required",
		})
	}

	parsed, err := url.Parse(req.WebhookURL)
	if err != nil || parsed.Scheme == "" || parsed.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(configureWebhookResponse{
			OK:      false,
			Message: "webhook_url must be a valid absolute URL",
		})
	}
	if parsed.Scheme != "http" && parsed.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(configureWebhookResponse{
			OK:      false,
			Message: "webhook_url scheme must be http or https",
		})
	}

	// Validate by sending a test GET request with a 3-second timeout.
	client := &http.Client{Timeout: 3 * time.Second}
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(configureWebhookResponse{
			OK:      false,
			Message: "webhook validation failed: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(configureWebhookResponse{
			OK:      false,
			Message: "webhook validation failed: non-2xx status " + resp.Status,
		})
	}

	// Save configuration (in-memory for this example).
	if err := saveWebhookURL(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(configureWebhookResponse{
			OK:      false,
			Message: "failed to save webhook configuration",
		})
	}

	return ctx.Status(fiber.StatusOK).JSON(configureWebhookResponse{
		OK:         true,
		WebhookURL: req.WebhookURL,
		Message:    "webhook configured",
	})
}

func saveWebhookURL(u string) error {
	u = strings.TrimSpace(u)
	if u == "" {
		return errors.New("empty url")
	}
	cfgMu.Lock()
	webhookURL = u
	cfgMu.Unlock()
	return nil
}

func getWebhookURL() string {
	cfgMu.RLock()
	defer cfgMu.RUnlock()
	return webhookURL
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	// Optional helper endpoint to view current config.
	app.Get("/webhook", func(c *fiber.Ctx) error {
		u := getWebhookURL()
		if u == "" {
			return c.Status(fiber.StatusNotFound).JSON(fiber.Map{
				"ok":      false,
				"message": "no webhook configured",
			})
		}
		return c.JSON(fiber.Map{
			"ok":          true,
			"webhook_url": u,
		})
	})

	log.Fatal(app.Listen(":8080"))
}

