	client := &http.Client{
		Timeout: 3 * time.Second,
	}
	httpReq, err := http.NewRequestWithContext(context.Background(), http.MethodGet, parsed.String(), nil)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(configureWebhookResponse{
			OK:      false,
			Message: "failed to build test request",
		})
	}

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.Status(fiber.StatusBadGateway).JSON(configureWebhookResponse{
