// validateResolvedIPs resolves host and ensures all returned IPs are allowed.
func validateResolvedIPs(ctx context.Context, host string) error {
	// If host is already an IP literal, validate it directly
	if ip, err := netip.ParseAddr(host); err == nil {
		if !isAllowedIP(net.IP(ip.AsSlice())) {
			return fmt.Errorf("blocked IP literal: %s", host)
		}
		return nil
	}

	ips, err := net.DefaultResolver.LookupIPAddr(ctx, host)
	if err != nil {
		return err
	}
	if len(ips) == 0 {
		return errors.New("no IPs resolved")
	}
	for _, ip := range ips {
		if !isAllowedIP(ip.IP) {
			return fmt.Errorf("blocked resolved IP: %s", ip.IP.String())
		}
	}
	return nil
}

// isAllowedIP blocks common SSRF targets: loopback, private, link-local, multicast, unspecified, etc.
func isAllowedIP(ip net.IP) bool {
	if ip == nil {
		return false
	}
	ip = normalizeIP(ip)
	if ip == nil {
		return false
	}

	// Standard library checks
	if ip.IsLoopback() || ip.IsUnspecified() || ip.IsMulticast() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return false
	}

	// net.IP doesn't have IsPrivate for all versions; implement common ranges.
	// IPv4 private ranges: 10/8, 172.16/12, 192.168/16
	if ip4 := ip.To4(); ip4 != nil {
		switch {
		case ip4[0] == 10:
			return false
		case ip4[0] == 172 && ip4[1]&0xF0 == 16:
			return false
		case ip4[0] == 192 && ip4[1] == 168:
			return false
		case ip4[0] == 127:
			return false
		case ip4[0] == 169 && ip4[1] == 254: // IPv4 link-local
			return false
		case ip4[0] == 0:
			return false
		case ip4[0] >= 224: // multicast/reserved
			return false
		}
		return true
	}

	// IPv6 blocks:
	// - fc00::/7 unique local
	// - fe80::/10 link-local
	// - ::1 loopback (already handled)
	// - :: unspecified (already handled)
	// - ff00::/8 multicast (already handled)
	ip16 := ip.To16()
	if ip16 == nil {
		return false
	}
	// fc00::/7
	if ip16[0]&0xFE == 0xFC {
		return false
	}
	// fe80::/10
	if ip16[0] == 0xFE && (ip16[1]&0xC0) == 0x80 {
		return false
	}

	return true
}

func normalizeIP(ip net.IP) net.IP {
	if ip4 := ip.To4(); ip4 != nil {
		return ip4
	}
	if ip16 := ip.To16(); ip16 != nil {
		return ip16
	}
	return nil
}

// Optional: a minimal app to wire the handler.
// Not required by the prompt, but keeps main.go complete and runnable.
func main() {
	app := fiber.New(fiber.Config{
		// Basic hardening
		DisableStartupMessage: true,
		JSONEncoder:           json.Marshal,
		JSONDecoder:           json.Unmarshal,
	})

	app.Post("/configure-webhook", ConfigureWebhook)

	port := os.Getenv("PORT")
	if port == "" {
		port = "3000"
	}
	_ = app.Listen(":" + port)
}

