package main

import (
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"net/url"
	"strings"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// webhookRequest represents the expected JSON request body
type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// simple in-memory storage for the configured webhook URL
var (
	webhookMu  sync.RWMutex
	webhookURL string
)

// ConfigureWebhook handles POST requests to configure a webhook URL.
// It validates the webhook URL by sending a GET request to it, then saves the configuration.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	req.WebhookURL = strings.TrimSpace(req.WebhookURL)

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.Parse(req.WebhookURL)
	if err != nil || parsedURL == nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}
	if parsedURL.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must include a host",
		})
	}

	// Create a custom HTTP client with timeout
	client := &http.Client{
		Timeout: 5 * time.Second,
	}

	// Validate the webhook by sending a GET request
	httpReq, err := http.NewRequest(http.MethodGet, req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create test request",
		})
	}
	httpReq.Header.Set("User-Agent", "fiber-webhook-configurator/1.0")

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to send test request to webhook URL: %v", err),
		})
	}
	// Drain body to allow connection reuse
	_, _ = io.Copy(io.Discard, resp.Body)
	_ = resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the configuration (in-memory for this example)
	webhookMu.Lock()
	webhookURL = req.WebhookURL
	webhookMu.Unlock()

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook configured successfully",
		"webhook_url": req.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	_ = app.Listen(":3000")
}

// Optional: helper to retrieve configured webhook URL
func getWebhookURL() string {
	webhookMu.RLock()
	defer webhookMu.RUnlock()
	return webhookURL
}

// Ensure unused imports don't occur if you remove main/getWebhookURL in your integration.
var _ = json.Valid

