// ConfigureWebhook receives JSON: {"webhook_url":"https://example.com/hook"}
// It validates the URL by sending a GET request with a 3-second timeout,
// then persists the configuration.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req configureWebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(configureWebhookResponse{
			OK:      false,
			Message: "invalid JSON body",
		})
	}

	req.WebhookURL = strings.TrimSpace(req.WebhookURL)
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(configureWebhookResponse{
			OK:      false,
			Message: "`webhook_url` is required",
		})
	}

	parsed, err := url.Parse(req.WebhookURL)
	if err != nil || parsed.Scheme == "" || parsed.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(configureWebhookResponse{
			OK:      false,
			Message: "invalid webhook_url",
		})
	}
	if parsed.Scheme != "http" && parsed.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(configureWebhookResponse{
			OK:      false,
			Message: "webhook_url must use http or https",
		})
	}

	status, err := testWebhookGET(req.WebhookURL, 3*time.Second)
	if err != nil {
		return ctx.Status(fiber.StatusBadGateway).JSON(configureWebhookResponse{
			OK:         false,
			Message:    "webhook validation failed: " + err.Error(),
			WebhookURL: req.WebhookURL,
			HTTPStatus: status,
		})
	}

	if err := saveWebhookConfig(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(configureWebhookResponse{
			OK:         false,
			Message:    "failed to save configuration: " + err.Error(),
			WebhookURL: req.WebhookURL,
			HTTPStatus: status,
		})
	}

	return ctx.Status(fiber.StatusOK).JSON(configureWebhookResponse{
		OK:          true,
		Message:     "webhook configured",
		WebhookURL:  req.WebhookURL,
		HTTPStatus:  status,
		StoredIn:    configFile,
		ValidatedAt: time.Now().UTC().Format(time.RFC3339),
	})
}

func testWebhookGET(rawURL string, timeout time.Duration) (int, error) {
	// Use a client with explicit timeout (requirement: 3 seconds).
	client := &http.Client{
		Timeout: timeout,
		Transport: &http.Transport{
			Proxy: http.ProxyFromEnvironment,
			DialContext: (&net.Dialer{
				Timeout:   timeout,
				KeepAlive: 30 * time.Second,
			}).DialContext,
			TLSHandshakeTimeout:   timeout,
			ResponseHeaderTimeout: timeout,
			ExpectContinueTimeout: 1 * time.Second,
			IdleConnTimeout:       30 * time.Second,
			MaxIdleConns:          10,
		},
	}

	req, err := http.NewRequestWithContext(context.Background(), http.MethodGet, rawURL, nil)
	if err != nil {
		return 0, err
	}

	resp, err := client.Do(req)
	if err != nil {
		return 0, err
	}
	defer resp.Body.Close()

	// Consider non-2xx responses as validation failures.
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return resp.StatusCode, errors.New("received non-2xx response")
	}

	return resp.StatusCode, nil
}

func saveWebhookConfig(webhookURL string) error {
	// Minimal persistence to a local JSON file.
	// In a real system, you might store this in a database or secret store.
	content := `{"webhook_url":"` + escapeJSONString(webhookURL) + `","updated_at":"` + time.Now().UTC().Format(time.RFC3339) + `"}`
	return os.WriteFile(configFile, []byte(content), 0o600)
}

// escapeJSONString performs minimal JSON string escaping for quotes and backslashes.
func escapeJSONString(s string) string {
	s = strings.ReplaceAll(s, `\`, `\\`)
	s = strings.ReplaceAll(s, `"`, `\"`)
	return s
}

