	"github.com/gofiber/fiber/v2"
)

type configureWebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

type configureWebhookResponse struct {
	OK         bool   `json:"ok"`
	Message    string `json:"message"`
	WebhookURL string `json:"webhook_url,omitempty"`
}

var (
	cfgMu      sync.RWMutex
	webhookURL string
)

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req configureWebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(configureWebhookResponse{
			OK:      false,
			Message: "invalid JSON body",
		})
	}

	u, err := validateWebhookURL(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(configureWebhookResponse{
			OK:      false,
			Message: err.Error(),
		})
	}

	// Test request with 3s timeout
	if err := testWebhookGET(u.String()); err != nil {
		return ctx.Status(fiber.StatusBadGateway).JSON(configureWebhookResponse{
			OK:      false,
			Message: "webhook validation failed: " + err.Error(),
		})
	}

	// Save configuration (in-memory for this example)
	cfgMu.Lock()
	webhookURL = u.String()
	cfgMu.Unlock()

	return ctx.Status(fiber.StatusOK).JSON(configureWebhookResponse{
		OK:         true,
		Message:    "webhook configured",
		WebhookURL: u.String(),
	})
}

func validateWebhookURL(raw string) (*url.URL, error) {
	if raw == "" {
		return nil, errors.New("webhook_url is required")
	}
	u, err := url.Parse(raw)
	if err != nil {
		return nil, errors.New("webhook_url is not a valid URL")
	}
	if u.Scheme != "http" && u.Scheme != "https" {
		return nil, errors.New("webhook_url must use http or https scheme")
	}
	if u.Host == "" {
		return nil, errors.New("webhook_url must include a host")
	}
	return u, nil
}

func testWebhookGET(target string) error {
	ctx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	req, err := http.NewRequestWithContext(ctx, http.MethodGet, target, nil)
	if err != nil {
		return err
	}
	req.Header.Set("User-Agent", "fiber-webhook-validator/1.0")

	client := &http.Client{
		Timeout: 3 * time.Second, // required: 3 seconds timeout
		Transport: &http.Transport{
			Proxy: http.ProxyFromEnvironment,
			DialContext: (&net.Dialer{
				Timeout:   3 * time.Second,
				KeepAlive: 30 * time.Second,
			}).DialContext,
			TLSHandshakeTimeout:   3 * time.Second,
			ResponseHeaderTimeout: 3 * time.Second,
			ExpectContinueTimeout: 1 * time.Second,
		},
	}

	resp, err := client.Do(req)
	if err != nil {
		return err
	}
	defer resp.Body.Close()

	// Consider any 2xx as success
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return errors.New("received non-2xx status: " + resp.Status)
	}
	return nil
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	// Optional helper endpoint to see current config
	app.Get("/webhook", func(c *fiber.Ctx) error {
		cfgMu.RLock()
		u := webhookURL
		cfgMu.RUnlock()
		return c.JSON(fiber.Map{"webhook_url": u})
	})

	port := os.Getenv("PORT")
	if port == "" {
		port = "8080"
	}

	log.Printf("listening on :%s", port)
	log.Fatal(app.Listen(":" + port))
}

