// readUpTo reads up to n bytes from r and discards them.
func readUpTo(r io.Reader, n int64) ([]byte, error) {
	lr := &limitedReader{r: r, n: n}
	return lr.readAll()
}

type limitedReader struct {
	r io.Reader
	n int64
}

func (l *limitedReader) readAll() ([]byte, error) {
	buf := make([]byte, 0, minInt64(l.n, 1024))
	tmp := make([]byte, 256)
	for l.n > 0 {
		if int64(len(tmp)) > l.n {
			tmp = tmp[:l.n]
		}
		n, err := l.r.Read(tmp)
		if n > 0 {
			buf = append(buf, tmp[:n]...)
			l.n -= int64(n)
		}
		if err != nil {
			// io.EOF included
			return buf, nil
		}
	}
	return buf, nil
}

func minInt64(a int64, b int) int {
	if a < int64(b) {
		return int(a)
	}
	return b
