			OK:      false,
			Message: "webhook_url must be a valid URL",
		})
	}
	if parsed.Scheme != "http" && parsed.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(configureWebhookResponse{
			OK:      false,
			Message: "webhook_url scheme must be http or https",
		})
	}

	// Validate webhook by sending a test GET request with a 3-second timeout.
	httpClient := &http.Client{
		Timeout: 3 * time.Second,
	}
	reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	httpReq, err := http.NewRequestWithContext(reqCtx, http.MethodGet, req.WebhookURL, nil)
	if err != nil {
