func validateHostNotPrivate(host string) error {
	// Block obvious localhost names early
	h := strings.ToLower(strings.TrimSpace(host))
	if h == "localhost" || strings.HasSuffix(h, ".localhost") {
		return errors.New("webhook URL host is not allowed")
	}

	// If it's an IP literal, validate directly
	if ip := net.ParseIP(h); ip != nil {
		if isDisallowedIP(ip) {
			return errors.New("webhook URL host resolves to a disallowed IP range")
		}
		return nil
	}

	// Resolve DNS and validate all A/AAAA records
	ips, err := net.DefaultResolver.LookupIP(context.Background(), "ip", host)
	if err != nil || len(ips) == 0 {
		return errors.New("webhook URL host could not be resolved")
	}
	for _, ip := range ips {
		if isDisallowedIP(ip) {
			return errors.New("webhook URL host resolves to a disallowed IP range")
		}
	}
	return nil
}

func isDisallowedIP(ip net.IP) bool {
	// Normalize
	if ip == nil {
		return true
	}
	// Go 1.17+ provides helpers
	if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}
	// Unspecified (0.0.0.0 / ::)
	if ip.IsUnspecified() {
		return true
	}
	// Multicast
	if ip.IsMulticast() {
		return true
	}
	// IPv6 unique local fc00::/7 (IsPrivate covers it in modern Go, keep explicit for safety)
	if ip.To4() == nil {
		if len(ip) == net.IPv6len {
			first := ip[0]
			if first&0xfe == 0xfc {
				return true
			}
		}
	}
	return false
}

