	app := fiber.New(fiber.Config{
		// Basic hardening
		BodyLimit: 1 * 1024 * 1024, // 1MB global limit
	})

	app.Post("/configure-webhook", ConfigureWebhook)

	port := os.Getenv("PORT")
	if port == "" {
		port = "3000"
	}
	_ = app.Listen(":" + port)
}

