	u, err := url.Parse(req.WebhookURL)
	if err != nil || u.Scheme == "" || u.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			OK:      false,
			Message: "webhook_url must be a valid absolute URL",
		})
	}
	if u.Scheme != "http" && u.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			OK:      false,
			Message: "webhook_url scheme must be http or https",
		})
	}

	// Validate by sending a GET request with a 3-second timeout.
	if err := testWebhookGET(req.WebhookURL, 3*time.Second); err != nil {
		return ctx.Status(fiber.StatusBadGateway).JSON(ConfigureWebhookResponse{
			OK:         false,
			Message:    "webhook validation failed: " + err.Error(),
			WebhookURL: req.WebhookURL,
		})
	}

	// Save configuration.
	configMu.Lock()
	configWebhook = req.WebhookURL
	configMu.Unlock()

	if err := saveConfig(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(ConfigureWebhookResponse{
			OK:         false,
			Message:    "failed to save configuration: " + err.Error(),
			WebhookURL: req.WebhookURL,
		})
	}

	return ctx.Status(fiber.StatusOK).JSON(ConfigureWebhookResponse{
		OK:         true,
		Message:    "webhook configured",
		WebhookURL: req.WebhookURL,
	})
}

func testWebhookGET(webhookURL string, timeout time.Duration) error {
	ctx, cancel := context.WithTimeout(context.Background(), timeout)
	defer cancel()

	req, err := http.NewRequestWithContext(ctx, http.MethodGet, webhookURL, nil)
	if err != nil {
		return err
	}
	req.Header.Set("User-Agent", "fiber-webhook-validator/1.0")

	client := &http.Client{
		Timeout: timeout, // required: 3 seconds in caller
		Transport: &http.Transport{
			Proxy: http.ProxyFromEnvironment,
			DialContext: (&net.Dialer{
				Timeout:   timeout,
				KeepAlive: 30 * time.Second,
			}).DialContext,
			TLSHandshakeTimeout:   timeout,
			ResponseHeaderTimeout: timeout,
			ExpectContinueTimeout: 1 * time.Second,
			IdleConnTimeout:       30 * time.Second,
			MaxIdleConns:          10,
		},
	}

	resp, err := client.Do(req)
	if err != nil {
		return err
	}
	defer resp.Body.Close()

	// Consider any 2xx as success.
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return errors.New("received non-2xx status: " + resp.Status)
	}
	return nil
}

func saveConfig(webhookURL string) error {
	f, err := os.Create(configFile)
	if err != nil {
		return err
	}
	defer f.Close()

	// Minimal JSON writing to avoid extra dependencies.
	escaped := strings.ReplaceAll(webhookURL, `\`, `\\`)
	escaped = strings.ReplaceAll(escaped, `"`, `\"`)
	_, err = f.WriteString(`{"webhook_url":"` + escaped + `"}` + "\n")
	return err
}

func loadConfig() error {
	b, err := os.ReadFile(configFile)
	if err != nil {
		return err
	}
	// Very small/naive parse for {"webhook_url":"..."}.
	s := string(b)
	key := `"webhook_url"`
	i := strings.Index(s, key)
	if i < 0 {
		return errors.New("missing webhook_url")
	}
	// Find first quote after colon.
	colon := strings.Index(s[i+len(key):], ":")
	if colon < 0 {
		return errors.New("invalid config")
	}
	rest := s[i+len(key)+colon+1:]
	rest = strings.TrimSpace(rest)
	if !strings.HasPrefix(rest, `"`) {
		return errors.New("invalid config")
	}
	rest = rest[1:]
	end := strings.Index(rest, `"`)
	if end < 0 {
		return errors.New("invalid config")
	}
	val := rest[:end]

	configMu.Lock()
	configWebhook = val
	configMu.Unlock()
	return nil
}

