func (s *webhookStore) Set(u string) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.url = u
}

func (s *webhookStore) Get() string {
	s.mu.RLock()
	defer s.mu.RUnlock()
	return s.url
