	parsed, err := url.Parse(req.WebhookURL)
	if err != nil || parsed.Scheme == "" || parsed.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(configureWebhookResponse{
			OK:      false,
			Message: "invalid webhook_url",
		})
	}
	if parsed.Scheme != "http" && parsed.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(configureWebhookResponse{
			OK:      false,
			Message: "webhook_url must use http or https",
		})
	}

	// Validate by sending a test GET request with a 3-second timeout.
	if err := testWebhookGET(req.WebhookURL, 3*time.Second); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(configureWebhookResponse{
			OK:      false,
			Message: "webhook validation failed: " + err.Error(),
		})
	}

	// Save configuration (simple file persistence for this example).
	if err := saveWebhookConfig(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(configureWebhookResponse{
			OK:      false,
			Message: "failed to save configuration: " + err.Error(),
		})
	}

	return ctx.Status(fiber.StatusOK).JSON(configureWebhookResponse{
		OK:         true,
		Message:    "webhook configured",
		WebhookURL: req.WebhookURL,
	})
}

func testWebhookGET(webhookURL string, timeout time.Duration) error {
	// Use a client with explicit timeout and a transport with sane defaults.
	client := &http.Client{
		Timeout: timeout,
		Transport: &http.Transport{
			Proxy: http.ProxyFromEnvironment,
			DialContext: (&net.Dialer{
				Timeout:   timeout,
				KeepAlive: 30 * time.Second,
			}).DialContext,
			TLSHandshakeTimeout:   timeout,
			ResponseHeaderTimeout: timeout,
			ExpectContinueTimeout: 1 * time.Second,
			IdleConnTimeout:       30 * time.Second,
			MaxIdleConns:          10,
		},
	}

	req, err := http.NewRequestWithContext(context.Background(), http.MethodGet, webhookURL, nil)
	if err != nil {
		return err
	}
	req.Header.Set("User-Agent", "fiber-webhook-configurator/1.0")

	resp, err := client.Do(req)
	if err != nil {
		return err
	}
	defer resp.Body.Close()

	// Treat non-2xx as failure.
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return errors.New("non-2xx response: " + resp.Status)
	}
	return nil
}

func saveWebhookConfig(webhookURL string) error {
	// Minimal JSON persistence without extra dependencies.
	// Stored as: {"webhook_url":"..."}
	content := `{"webhook_url":` + toJSONString(webhookURL) + `}` + "\n"
	return os.WriteFile(webhookConfigFile, []byte(content), 0o600)
}

func toJSONString(s string) string {
	// Simple JSON string escaper sufficient for URLs.
	var b strings.Builder
	b.Grow(len(s) + 2)
	b.WriteByte('"')
	for _, r := range s {
		switch r {
		case '\\':
			b.WriteString(`\\`)
		case '"':
			b.WriteString(`\"`)
		case '\b':
			b.WriteString(`\b`)
		case '\f':
			b.WriteString(`\f`)
		case '\n':
			b.WriteString(`\n`)
		case '\r':
			b.WriteString(`\r`)
		case '\t':
			b.WriteString(`\t`)
		default:
			// Control characters must be escaped in JSON.
			if r < 0x20 {
				// \u00XX
				hex := "0123456789abcdef"
				b.WriteString(`\u00`)
				b.WriteByte(hex[(r>>4)&0xF])
				b.WriteByte(hex[r&0xF])
			} else {
				b.WriteRune(r)
			}
		}
	}
	b.WriteByte('"')
	return b.String()
}

