// validatePublicWebhookHost blocks common SSRF targets: localhost, link-local, private ranges,
// and internal-reserved names.
func validatePublicWebhookHost(host string) error {
	h := strings.ToLower(strings.TrimSpace(host))
	if h == "" {
		return errors.New("empty host")
	}

	// Block obvious internal names
	switch h {
	case "localhost", "localhost.localdomain":
		return errors.New("localhost not allowed")
	}
	if strings.HasSuffix(h, ".localhost") {
		return errors.New("localhost suffix not allowed")
	}

	// If it's an IP literal, validate directly
	if ip := net.ParseIP(h); ip != nil {
		if isDisallowedIP(ip) {
			return errors.New("ip not allowed")
		}
		return nil
	}

	// Resolve DNS and ensure all A/AAAA are public
	ips, err := net.DefaultResolver.LookupIP(context.Background(), "ip", h)
	if err != nil || len(ips) == 0 {
		return errors.New("host resolution failed")
	}
	for _, ip := range ips {
		if isDisallowedIP(ip) {
			return errors.New("resolved ip not allowed")
		}
	}
	return nil
